import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  listenAuction, listenPlayers, listenRecords,
  startAuction, closeAuction, logoutPlayer,
  getGroupSettings, resetAllWins
} from '../firebase/services';
import Countdown from '../components/Countdown';
import toast from 'react-hot-toast';

export default function AdminDashboard() {
  const navigate = useNavigate();
  const [auction, setAuction] = useState(null);
  const [players, setPlayers] = useState([]);
  const [records, setRecords] = useState([]);
  const [settings, setSettings] = useState(null);
  const [tab, setTab] = useState('auction');
  const [loading, setLoading] = useState(false);
  const [auctionLoaded, setAuctionLoaded] = useState(false);

  useEffect(() => {
    const unsubs = [
      listenAuction(data => { setAuction(data); setAuctionLoaded(true); }),
      listenPlayers(setPlayers),
      listenRecords(setRecords),
    ];
    const loadSettings = async () => {
      const s = await getGroupSettings();
      setSettings(s);
    };
    loadSettings();
    return () => unsubs.forEach(u => u());
  }, []);

  const handleStartAuction = async () => {
    if (!settings) return toast.error('No group settings found. Set up the group first.');
    const pendingPlayers = players.filter(p => !p.hasWon && !p.isAdmin);
    if (pendingPlayers.length === 0) return toast.error('All players have won! Reset the cycle first.');
    const isLastPlayer = pendingPlayers.length === 1;
    setLoading(true);
    try {
      await startAuction(settings, isLastPlayer);
      const msg = isLastPlayer
        ? `Last player! ${pendingPlayers[0]?.name} wins automatically â€” close to confirm.`
        : 'Auction started! 15 minutes on the clock.';
      toast.success(msg);
    } catch (err) {
      toast.error(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleCloseAuction = async () => {
    if (!auction?.active) return;
    if (!auction.isLastPlayer && !auction.currentBidder) return toast.error('No bids placed yet. Cannot close.');
    const confirmMsg = auction.isLastPlayer
      ? `Confirm last player wins â‚ą${auction.totalPool?.toLocaleString('en-IN')} (full pool)?`
      : `Close auction? ${auction.currentBidderName} wins with â‚ą${auction.currentBid?.toLocaleString('en-IN')} bid.`;
    if (!window.confirm(confirmMsg)) return;
    setLoading(true);
    try {
      const result = await closeAuction();
      toast.success(`đźŹ† ${result.winnerName} wins â‚ą${result.winnerReceives?.toLocaleString('en-IN')}!`);
    } catch (err) {
      toast.error(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleResetCycle = async () => {
    if (!window.confirm('Reset ALL player wins? This starts a new BC cycle.')) return;
    setLoading(true);
    try {
      await resetAllWins();
      toast.success('New cycle started! All wins reset.');
    } catch (err) {
      toast.error(err.message);
    } finally {
      setLoading(false);
    }
  };

  const wonPlayers = players.filter(p => p.hasWon);
  const pendingPlayers = players.filter(p => !p.hasWon);

  return (
    <div className="page">
      <nav className="navbar">
        <div>
          <div className="navbar-brand">âš™ď¸Ź Admin Panel</div>
          <div className="navbar-sub">BC Circle Control</div>
        </div>
        <div style={{ display: 'flex', gap: 8 }}>
          <button className="btn btn-ghost btn-sm" onClick={() => navigate('/admin/setup')}>Setup</button>
          <button className="btn btn-ghost btn-sm" onClick={logoutPlayer}>Logout</button>
        </div>
      </nav>

      {/* Group Stats */}
      {settings && (
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: 10, marginBottom: 16 }}>
          {[
            { label: 'Players', value: settings.totalPlayers },
            { label: 'Monthly', value: `â‚ą${settings.monthlyAmount?.toLocaleString('en-IN')}` },
            { label: 'Pool', value: `â‚ą${(settings.monthlyAmount * settings.totalPlayers)?.toLocaleString('en-IN')}` }
          ].map(s => (
            <div key={s.label} style={{ background: 'var(--bg-card)', border: '1px solid var(--border)', borderRadius: 12, padding: '14px 10px', textAlign: 'center' }}>
              <div style={{ color: 'var(--text-muted)', fontSize: '0.68rem', textTransform: 'uppercase', letterSpacing: '0.06em', marginBottom: 4 }}>{s.label}</div>
              <div style={{ color: 'var(--gold)', fontWeight: 700, fontSize: '1rem', fontFamily: 'Playfair Display, serif' }}>{s.value}</div>
            </div>
          ))}
        </div>
      )}

      <div className="tabs">
        <div className={`tab ${tab === 'auction' ? 'active' : ''}`} onClick={() => setTab('auction')}>đź”´ Auction</div>
        <div className={`tab ${tab === 'players' ? 'active' : ''}`} onClick={() => setTab('players')}>đź‘Ą Players</div>
        <div className={`tab ${tab === 'records' ? 'active' : ''}`} onClick={() => setTab('records')}>đź“‹ Records</div>
      </div>

      {/* AUCTION TAB */}
      {tab === 'auction' && (
        <>
          {!auctionLoaded && <div className="spinner" />}

          {/* Controls */}
          <div className="card">
            <div className="card-header">
              <span className="card-title">Auction Controls</span>
              <span className={`status-dot ${auction?.active ? 'live' : 'closed'}`}></span>
            </div>

            {!auction?.active && (
              <div>
                <p style={{ color: 'var(--text-muted)', fontSize: '0.85rem', marginBottom: 16 }}>
                  Start a new auction session. Players will have 15 minutes to bid.
                  Pending players: <strong style={{ color: 'var(--gold)' }}>{pendingPlayers.length}</strong>
                </p>
                <button
                  className="btn btn-green btn-full"
                  onClick={handleStartAuction}
                  disabled={loading || !settings || pendingPlayers.length === 0}
                >
                  {loading ? 'Starting...' : 'â–¶ Start This Month\'s Auction'}
                </button>
                {!settings && (
                  <button className="btn btn-primary btn-full" style={{ marginTop: 10 }} onClick={() => navigate('/admin/setup')}>
                    Setup Group First â†’
                  </button>
                )}
              </div>
            )}

            {auction?.active && !auction?.closed && (
              <div>
                <div style={{ marginBottom: 16, textAlign: 'center' }}>
                  <Countdown endsAt={auction.endsAt} />
                  <div style={{ color: 'var(--text-muted)', fontSize: '0.75rem', marginTop: 4 }}>remaining</div>
                </div>

                <div style={{ padding: '16px', background: 'var(--bg-raised)', borderRadius: 12, marginBottom: 16 }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 8 }}>
                    <span style={{ color: 'var(--text-muted)', fontSize: '0.85rem' }}>Current Bid</span>
                    <span style={{ color: 'var(--gold)', fontWeight: 700, fontSize: '1.1rem', fontFamily: 'Playfair Display, serif' }}>
                      â‚ą{auction.currentBid?.toLocaleString('en-IN')}
                    </span>
                  </div>
                  <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 8 }}>
                    <span style={{ color: 'var(--text-muted)', fontSize: '0.85rem' }}>Leading Bidder</span>
                    <span style={{ fontWeight: 500 }}>{auction.currentBidderName || 'â€”'}</span>
                  </div>
                  <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                    <span style={{ color: 'var(--text-muted)', fontSize: '0.85rem' }}>Total Bids</span>
                    <span>{auction.bids?.length || 0}</span>
                  </div>
                </div>

                <button
                  className="btn btn-danger btn-full"
                  onClick={handleCloseAuction}
                  disabled={loading || !auction.currentBidder}
                >
                  {loading ? 'Closing...' : 'âŹą Close Auction & Declare Winner'}
                </button>
                <p style={{ color: 'var(--text-muted)', fontSize: '0.75rem', textAlign: 'center', marginTop: 8 }}>
                  Auction also closes automatically when timer ends.
                </p>
              </div>
            )}

            {auction?.closed && auction?.result && (
              <div>
                <div style={{ textAlign: 'center', padding: '16px', background: 'rgba(201,168,76,0.1)', borderRadius: 12, marginBottom: 16 }}>
                  <div style={{ fontSize: '2rem' }}>đźŹ†</div>
                  <div style={{ color: 'var(--gold)', fontWeight: 700, fontFamily: 'Playfair Display, serif', fontSize: '1.2rem' }}>{auction.result.winnerName}</div>
                  <div style={{ color: 'var(--green)', fontWeight: 700, fontSize: '1.5rem', fontFamily: 'Playfair Display, serif' }}>
                    â‚ą{auction.result.winnerReceives?.toLocaleString('en-IN')}
                  </div>
                  <div style={{ color: 'var(--text-muted)', fontSize: '0.8rem', marginTop: 4 }}>
                    Bonus per player: â‚ą{auction.result.perPlayerBonus?.toLocaleString('en-IN')}
                  </div>
                </div>

                <div style={{ display: 'flex', gap: 10 }}>
                  <button
                    className="btn btn-green btn-full"
                    onClick={handleStartAuction}
                    disabled={loading || pendingPlayers.length === 0}
                  >
                    {pendingPlayers.length === 0 ? 'All Won!' : 'â–¶ Next Month Auction'}
                  </button>
                </div>
              </div>
            )}
          </div>

          {/* Cycle Management */}
          <div className="card">
            <div className="card-header">
              <span className="card-title">Cycle Management</span>
              <span className="badge badge-muted">{wonPlayers.length}/{players.length} done</span>
            </div>
            <div style={{ background: 'var(--bg-raised)', borderRadius: 10, height: 8, overflow: 'hidden', marginBottom: 12 }}>
              <div style={{
                height: '100%',
                background: 'linear-gradient(90deg, var(--gold), var(--gold-dark))',
                width: `${players.length > 0 ? (wonPlayers.length / players.length) * 100 : 0}%`,
                transition: 'width 0.5s ease',
                borderRadius: 10
              }} />
            </div>
            <p style={{ color: 'var(--text-muted)', fontSize: '0.85rem', marginBottom: 16 }}>
              {players.length - wonPlayers.length} players remaining in this cycle.
              {wonPlayers.length === players.length && ' All players have won! Start a new cycle.'}
            </p>
            {wonPlayers.length === players.length && (
              <button className="btn btn-primary btn-full" onClick={handleResetCycle} disabled={loading}>
                đź”„ Start New Cycle
              </button>
            )}
          </div>
        </>
      )}

      {/* PLAYERS TAB */}
      {tab === 'players' && (
        <div className="card">
          <div className="card-header">
            <span className="card-title">All Players</span>
            <button className="btn btn-ghost btn-sm" onClick={() => navigate('/admin/setup')}>+ Add</button>
          </div>
          {players.map(p => (
            <div key={p.id} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '12px 0', borderBottom: '1px solid rgba(201,168,76,0.08)' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                <div className="player-avatar">{p.isAdmin ? 'âš™ď¸Ź' : p.name?.[0]?.toUpperCase()}</div>
                <div>
                  <div style={{ fontWeight: 500 }}>{p.name} {p.isAdmin && <span style={{ color: 'var(--text-muted)', fontSize: '0.75rem' }}>(admin)</span>}</div>
                  <div style={{ color: 'var(--text-muted)', fontSize: '0.75rem' }}>{p.email}</div>
                </div>
              </div>
              <div>
                {p.hasWon
                  ? <span className="badge badge-gold">Won {p.wonMonth}</span>
                  : <span className="badge badge-muted">Pending</span>
                }
              </div>
            </div>
          ))}
        </div>
      )}

      {/* RECORDS TAB */}
      {tab === 'records' && (
        <div className="card" style={{ overflowX: 'auto' }}>
          <div className="card-header">
            <span className="card-title">All Records</span>
            <span className="badge badge-muted">{records.length} months</span>
          </div>
          {records.length === 0 ? (
            <div style={{ color: 'var(--text-muted)', textAlign: 'center', padding: '20px 0' }}>No records yet.</div>
          ) : (
            <table className="records-table">
              <thead>
                <tr>
                  <th>Month</th>
                  <th>Winner</th>
                  <th>Bid</th>
                  <th>Got</th>
                  <th>Bonus</th>
                </tr>
              </thead>
              <tbody>
                {records.map(r => (
                  <tr key={r.id}>
                    <td><span className="badge badge-muted">{r.month}</span></td>
                    <td style={{ fontWeight: 500 }}>{r.winnerName}</td>
                    <td style={{ color: 'var(--accent)' }}>â‚ą{r.winningBid?.toLocaleString('en-IN')}</td>
                    <td style={{ color: 'var(--green)', fontWeight: 600 }}>â‚ą{r.winnerReceives?.toLocaleString('en-IN')}</td>
                    <td style={{ color: 'var(--gold)' }}>â‚ą{r.perPlayerBonus?.toLocaleString('en-IN')}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      )}
    </div>
  );
}
